module asyn_fifo #(
    parameter DEPTH = 16,
    parameter WIDTH = 8
) (
    input wclk,
    input rclk,
    input rst_n,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output wfull,
    output rempty,
    output [WIDTH-1:0] rdata
);

localparam ADDR_WIDTH = $clog2(DEPTH);

// Dual-Port RAM instance
reg [WIDTH-1:0] mem [0:DEPTH-1];
reg [ADDR_WIDTH-1:0] wptr, rptr;
reg wenc, renc;

// Write operation
always @(posedge wclk or negedge rst_n) begin
    if (!rst_n) begin
        wptr <= 0;
        wenc <= 0;
    end
    else if (winc && !wfull) begin
        mem[wptr] <= wdata;
        wptr <= wptr + 1;
        wenc <= 1;
    end
    else begin
        wenc <= 0;
    end
end

// Read operation
always @(posedge rclk or negedge rst_n) begin
    if (!rst_n) begin
        rptr <= 0;
        renc <= 0;
    end
    else if (rinc && !rempty) begin
        rptr <= rptr + 1;
        renc <= 1;
    end
    else begin
        renc <= 0;
    end
end

// Gray code conversion for pointers
function [ADDR_WIDTH-1:0] bin2gray(input [ADDR_WIDTH-1:0] bin);
    begin
        bin2gray = bin ^ (bin >> 1);
    end
endfunction

wire [ADDR_WIDTH-1:0] wptr_gray, rptr_gray;
assign wptr_gray = bin2gray(wptr);
assign rptr_gray = bin2gray(rptr);

// Full/empty flags
assign wfull = (wptr_gray == (rptr_gray ^ {1'b1, {(ADDR_WIDTH-1){1'b0}}}));
assign rempty = (wptr_gray == rptr_gray);

// Read data output
assign rdata = mem[rptr];

endmodule
